//// Created by Song on 2026/1/10.//#include "interface.h"#include "../Log/log.h"#include <sstream>#include <vector>#include <iomanip>#include <unordered_map>#include <android/log.h>fun::function::function(void* dqil2cppBase,                        void *pCodeRegistration,                        void *pMetadataRegistration,                        void *pGlobalMetadataHeader,                        void* pMetadataImagesTable) :        li2cppApi::cUnityApi(dqil2cppBase,                             static_cast<Il2CppCodeRegistration *>(pCodeRegistration),                             static_cast<Il2CppMetadataRegistration *>(pMetadataRegistration),                             static_cast<Il2CppGlobalMetadataHeader *>(pGlobalMetadataHeader),                             static_cast<Il2CppImageGlobalMetadata *>(pMetadataImagesTable)){    initPackPath("com.tencent.lolm");    // 初始化文件输出流    auto initFile = [&](std::shared_ptr<cMyfile>& file, const std::string& path) {        if (file == nullptr) {            file = std::make_shared<cMyfile>(path);            if (file) file->openFile(cMyfile::FileMode::ReadWrite);        }    };    initFile(m_outlog, m_pathlog);    if(m_pClassInfo){        m_pClassInfo = std::make_shared<std::list<std::shared_ptr<CClassInfo>>>();    }}/** * 日志记录函数 * 负责将调试信息写入到 /data/data/com.DefaultCompany.Demo1/cache/log.cs */bool fun::function::writeLog(std::string str) {    if (m_outlog == nullptr) {        return false;    }    // 格式化输出，增加标识前缀    //std::string out = "[SFK] : " + str;    //LOG(LOG_LEVEL_INFO,"%s",str.c_str());    // 调用你文件类 cMyfile 的接口写入一行    m_outlog->writeLine(str.c_str());    // 实时冲刷缓冲区，防止日志丢失    m_outlog->flush();    return true;}void fun::function::initPackPath(std::string strPackName) {    m_pathlog = "/data/data/"+strPackName+"/files/testlog.cs";}void*fun::function::GetStaticMember(std::string pMainModuleName, std::string pModuleName,                                    std::string pClassName, std::string ptemplateName,                                    std::string pStaticName) {    LOG(LOG_LEVEL_INFO,"[Test Game] GetStaticMember call");    if(m_pClassInfo && !m_pClassInfo->empty()){        for(auto&ite:*m_pClassInfo){            //判断模块名是否一致，如果一致说明在此链表中            if(*ite->m_ModuleData->m_pName == pModuleName){                LOG(LOG_LEVEL_INFO,"[Test Game] pModuleName : %s",pModuleName.c_str());                //指向当前模块存储的所有数据结构开头,遍历当前所有结构                for (auto&pClassStruct:*ite->m_pClassStruct) {                    //判断类的名字，并判断泛型是否一致                    if(*pClassStruct.m_pClassData->m_pName == pClassName &&                    (ptemplateName == "" ? 1 : *pClassStruct.m_pClassData->m_pGenericsName == ptemplateName)){                        LOG(LOG_LEVEL_INFO,"[Test Game] pClassName : %s ptemplateName : %s",pClassName.c_str(),ptemplateName.c_str());                        //如果找到类就遍历类下面的静态成员名，                        for (auto& pStaticStruct : *pClassStruct.m_pVectorStaticData) {                            // ================= 开始检索静态字段 =================                            if (*pStaticStruct->m_Data.m_pName == pStaticName) {                                LOG(LOG_LEVEL_INFO, "[Test Game][Step 1] 匹配到目标字段名称: %s", pStaticName.c_str());                                // 1. 获取 FieldInfo 指针 (保留位运算逻辑)                                uint64_t rawFieldPtr = (uint64_t)pStaticStruct->fieldInfo;                                FieldInfo *fieldInfo = (FieldInfo*)(rawFieldPtr & 0x000000FFFFFFFFFF);                                if (fieldInfo == nullptr) {                                    LOG(LOG_LEVEL_ERROR, "[Test Game][Error] fieldInfo 地址解析后为空！原始值: 0x%llX", rawFieldPtr);                                    return nullptr;                                }                                LOG(LOG_LEVEL_INFO, "[Test Game][Step 2] 字段信息已定位: fieldInfoPtr=%p", fieldInfo);                                // 2. 获取该字段所属的类                                Il2CppClass* parentClass = il2cpp_field_get_parent(fieldInfo);                                if (parentClass == nullptr) {                                    LOG(LOG_LEVEL_ERROR, "[Test Game][Error] 无法获取字段 %s 所属的 ParentClass", pStaticName.c_str());                                    return nullptr;                                }                                const char* className = parentClass->name;                                LOG(LOG_LEVEL_INFO, "[Test Game][Step 3] 字段所属类: %s", className ? className : "Unknown");                                // 3. 检查类是否初始化 (static_fields 是否为空)                                if (parentClass->static_fields == nullptr) {                                    LOG(LOG_LEVEL_WARN, "[Test Game][Warning] 目标类 %s 尚未初始化，尝试手动调用 il2cpp_runtime_class_init...", className);                                    // 尝试手动初始化类                                    il2cpp_runtime_class_init(parentClass);                                    // 再次检查初始化结果                                    if (parentClass->static_fields == nullptr) {                                        LOG(LOG_LEVEL_ERROR, "[Test Game][Fatal] 类 %s 初始化失败，static_fields 仍然为空。无法读取静态值。", className);                                        return nullptr;                                    } else {                                        LOG(LOG_LEVEL_INFO, "[Test Game][Success] 类 %s 手动初始化成功！static_fields 地址: %p", className, parentClass->static_fields);                                    }                                } else {                                    LOG(LOG_LEVEL_INFO, "[Test Game][Info] 类 %s 已处于初始化状态。", className);                                }                                // 4. 再次检查该字段是否真的是静态字段                                uint32_t attrs = il2cpp_field_get_flags(fieldInfo);                                if (!(attrs & FIELD_ATTRIBUTE_STATIC)) {                                    LOG(LOG_LEVEL_ERROR, "[Test Game][Error] 字段 %s 并非静态字段(FIELD_ATTRIBUTE_STATIC 为 False)！", pStaticName.c_str());                                    return nullptr;                                }                                // 5. 安全获取数值                                uint64_t valBuffer = 0;                                // 辅助调试：记录字段相对于静态区域基址的内存偏移                                size_t offset = fieldInfo->offset;                                LOG(LOG_LEVEL_INFO, "[Test Game][Step 4] 准备从静态内存偏移 0x%X 处读取...", (uint32_t)offset);                                // 执行 IL2CPP 原生获取函数                                this->il2cpp_field_static_get_value(fieldInfo, &valBuffer);                                // 6. 最终结果输出                                LOG(LOG_LEVEL_INFO, "[Test Game][Final] 获取成功! [%s] -> Value: %llu (Hex: 0x%llX)",                                    pStaticName.c_str(), valBuffer, valBuffer);                                return (void*)valBuffer;                            }                        }                    }                }            }        }    }    return nullptr;}void*fun::function::GetMethodFun(std::string pMainModuleName, std::string pModuleName,                                 std::string pClassName, std::string ptemplateName,                                 std::string pMethodName,std::string pMethodtemplateName){        LOG(LOG_LEVEL_INFO,"[Test Game] GetMethodFun call");        if(m_pClassInfo && !m_pClassInfo->empty()) {            for(auto&ite:*m_pClassInfo) {                //判断模块名是否一致，如果一致说明在此链表中                if (*ite->m_ModuleData->m_pName == pModuleName) {                    LOG(LOG_LEVEL_INFO, "[Test Game] pModuleName : %s", pModuleName.c_str());                    //指向当前模块存储的所有数据结构开头,遍历当前所有结构                    for (auto &pClassStruct: *ite->m_pClassStruct) {                        //判断类的名字，并判断泛型是否一致                        if (*pClassStruct.m_pClassData->m_pName == pClassName &&                        (ptemplateName == "" ? 1 :*pClassStruct.m_pClassData->m_pGenericsName == ptemplateName)) {                            LOG(LOG_LEVEL_INFO, "[Test Game] pClassName : %s ptemplateName : %s",pClassName.c_str(), ptemplateName.c_str());                            //遍历方法表获取地址                            for (auto&pMethodData:*pClassStruct.m_pVectorFunctionData) {                                if(*pMethodData->m_pName == pMethodName){                                    if(pMethodtemplateName==""){                                        return (void*)pMethodData->m_offset;                                    }                                    if(*pMethodData->m_pGenericsName ==pMethodtemplateName){                                        return (void*)pMethodData->m_offset;                                    }                                }                            }                        }                    }                }            }        }    return nullptr;}std::shared_ptr<fun::CClassInfo>fun::function::AddModuleInfo(std::shared_ptr<fun::CClassInfo> pData,                             std::string pModuleName, uint64_t offset) {    if(pModuleName.empty() && pData==nullptr){        return nullptr;    }    auto p = std::make_shared<CData>();    if(p){        p->m_pName = std::make_shared<std::string>(pModuleName);        p->m_offset = offset;        //将模块信息添加到指定的CClassInfo结构中        pData->m_ModuleData = p;    }    return pData;}std::shared_ptr<fun::CClassData>fun::function::AddClassStructInfo(std::shared_ptr<fun::CClassData> pData,std::string pClassName,                                  std::string pGenericsName,uint64_t offset) {    if(pData == nullptr && pClassName.empty()){        return nullptr;    }    auto p = std::make_shared<fun::CTemplateData>();    if(p){        p->m_pName = std::make_shared<std::string>(pClassName);        if(!pGenericsName.empty()){            p->m_pGenericsName = std::make_shared<std::string>(pGenericsName);        }        p->m_offset = offset;        pData->m_pClassData = p;    }    return pData;}std::shared_ptr<std::vector<std::shared_ptr<fun::CFieldData>>>fun::function::AddVectorStaticData(std::shared_ptr<std::vector<std::shared_ptr<fun::CFieldData>>> pData,                                   std::string pStaticName,FieldInfo *fieldInfo, uint64_t offset) {    if (pData == nullptr && pStaticName.empty()) {        return nullptr;    }    auto p = std::make_shared<fun::CFieldData>();    if (p) {        p->m_Data.m_pName = std::make_shared<std::string>(pStaticName);        p->m_Data.m_offset = offset;        p->fieldInfo = fieldInfo;        pData->push_back(p);    }    return pData;}std::shared_ptr<std::vector<std::shared_ptr<fun::CTemplateData>>>fun::function::AddVectorFunctionData(std::shared_ptr<std::vector<std::shared_ptr<fun::CTemplateData>>> pData,                                     std::string pClassName, std::string pGenericsName,uint64_t offset) {    if (pData == nullptr && pClassName.empty()) {        return nullptr;    }    auto p = std::make_shared<fun::CTemplateData>();    if (p) {        p->m_pName = std::make_shared<std::string>(pClassName);        if (!pGenericsName.empty()) {            p->m_pGenericsName = std::make_shared<std::string>(pGenericsName);        }        p->m_offset = offset;        pData->push_back(p);    }    return pData;}std::shared_ptr<std::list<std::shared_ptr<fun::CClassInfo>>>fun::function::AddClassStruct(std::shared_ptr<std::list<std::shared_ptr<fun::CClassInfo>>> pData,                              std::shared_ptr<fun::CData> pModuleData,std::shared_ptr<std::vector<fun::CClassData>> pClassStruct) {    if (pData == nullptr) {        return nullptr;    }    auto p = std::make_shared<fun::CClassInfo>();    if (p) {        p->m_ModuleData = pModuleData;        p->m_pClassStruct = pClassStruct;        pData->push_back(p);    }    return pData;}Il2CppClass* fun::function::FindClassByName(std::string pMainModuleName,std::string pModuleName, std::string pClassName , std::string pTemplateName ) {    LOG(LOG_LEVEL_INFO, "[Test Game] FindClassByName call, className: %s, moduleName: %s, templateName: %s",        pClassName.c_str(), pModuleName.c_str(), pTemplateName.c_str());    if (pClassName.empty()) {        LOG(LOG_LEVEL_ERROR, "[Test Game] FindClassByName: 类名参数为空!");        return nullptr;    }    if (m_pClassInfo && !m_pClassInfo->empty()) {        // 遍历所有模块        for (auto& ite : *m_pClassInfo) {            if (!ite || !ite->m_pClassStruct) continue;            // 如果指定了模块名，则先过滤模块            if (!pModuleName.empty()) {                if (!ite->m_ModuleData || !ite->m_ModuleData->m_pName ||                    *ite->m_ModuleData->m_pName != pModuleName) {                    continue;                }            }            // 遍历当前模块下的所有类            for (auto& pClassStruct : *ite->m_pClassStruct) {                if (!pClassStruct.m_pClassData || !pClassStruct.m_pClassData->m_pName) continue;                // 匹配类名                if (*pClassStruct.m_pClassData->m_pName != pClassName) continue;                // 如果指定了泛型名，则进一步匹配泛型                if (!pTemplateName.empty()) {                    if (!pClassStruct.m_pClassData->m_pGenericsName ||                        *pClassStruct.m_pClassData->m_pGenericsName != pTemplateName) {                        continue;                    }                }                // 匹配成功，返回 Il2CppClass* 类对象地址                LOG(LOG_LEVEL_INFO, "[Test Game] FindClassByName: 匹配成功 [%s], 模块: %s, Il2CppClass*: %p",                    pClassName.c_str(),                    ite->m_ModuleData && ite->m_ModuleData->m_pName ? ite->m_ModuleData->m_pName->c_str() : "Unknown",                    pClassStruct.m_pKlass);                return pClassStruct.m_pKlass;            }        }    }    LOG(LOG_LEVEL_WARN, "[Test Game] FindClassByName: 未找到类 [%s]", pClassName.c_str());    return nullptr;}fun::function::~function() {    DeepClearClassInfo();       //释放 m_pClassInfo 成员    if (m_outlog) { m_outlog->flush(); m_outlog->closeFile(); }}void fun::function::DeepClearClassInfo() {    if (m_pClassInfo == nullptr) return;    // 1. 遍历 list 中的每一个 CClassInfo    for (auto it = m_pClassInfo->begin(); it != m_pClassInfo->end(); ++it) {        auto pClassInfo = *it;        if (!pClassInfo) continue;        // --- 释放 CClassInfo 内部成员 ---        // 释放模块信息        if (pClassInfo->m_ModuleData) {            pClassInfo->m_ModuleData.reset();        }        // 遍历并释放类结构 vector (m_pClassStruct)        if (pClassInfo->m_pClassStruct) {            for (auto& classData : *(pClassInfo->m_pClassStruct)) {                // 释放 CClassData 内部的嵌套容器                if (classData.m_pClassData) {                    classData.m_pClassData.reset();                }                // 显式清空静态数据 vector                if (classData.m_pVectorStaticData) {                    classData.m_pVectorStaticData->clear();                    classData.m_pVectorStaticData.reset();                }                // 显式清空函数数据 vector                if (classData.m_pVectorFunctionData) {                    classData.m_pVectorFunctionData->clear();                    classData.m_pVectorFunctionData.reset();                }            }            pClassInfo->m_pClassStruct->clear();            pClassInfo->m_pClassStruct.reset();        }    }    // 2. 最后清空主链表并重置顶层指针    m_pClassInfo->clear();    m_pClassInfo.reset();    m_pClassInfo = nullptr;}void fun::function::fillingClassInfo() {    // 初始化顶层全局链表    if (m_pClassInfo == nullptr) {        m_pClassInfo = std::make_shared<std::list<std::shared_ptr<CClassInfo>>>();    }    char szBuf[0x1000] = {0};    std::string Buf = "";    auto domain = il2cpp_domain_get();    size_t size;    auto assemblies = il2cpp_domain_get_assemblies(domain, &size);    LOG(LOG_LEVEL_INFO, "======== Start Filling Class Info (Assemblies: %zu) ========", size);    for (size_t i = 0; i < size; ++i) {        auto image = il2cpp_assembly_get_image(assemblies[i]);        const char* imageName = il2cpp_image_get_name(image);        Buf = "[Module] Processing ";        Buf.append(imageName);        writeLog(Buf);        //LOG(LOG_LEVEL_INFO, "[Test MyStartPoint] %s", Buf.c_str());        // 1. 准备模块数据        auto pModuleData = std::make_shared<CData>();        pModuleData->m_pName = std::make_shared<std::string>(imageName);        pModuleData->m_offset = (uint64_t)image;        auto pClassStructVec = std::make_shared<std::vector<CClassData>>();        auto classCount = il2cpp_image_get_class_count(image);        for (int j = 0; j < classCount; ++j) {            auto klass = il2cpp_image_get_class(image, j);            if (!klass) continue;            // 2. 准备类的数据结构            auto pClassDataObj = std::make_shared<CClassData>();            pClassDataObj->m_pVectorStaticData = std::make_shared<std::vector<std::shared_ptr<CFieldData>>>();            pClassDataObj->m_pVectorFunctionData = std::make_shared<std::vector<std::shared_ptr<CTemplateData>>>();            // 3. 获取类名            const char* ns = il2cpp_class_get_namespace(const_cast<Il2CppClass *>(klass));            const char* name = il2cpp_class_get_name(const_cast<Il2CppClass *>(klass));            std::string className = (ns && *ns) ? (std::string(ns) + "." + name) : name;            Buf = "[className] name ";            Buf.append(name);            writeLog(Buf);            //LOG(LOG_LEVEL_INFO, "[Test MyStartPoint]%s", Buf.c_str());            std::string genericsName = "";            auto type = il2cpp_class_get_type(const_cast<Il2CppClass *>(klass));            const char* pTypeName = il2cpp_type_get_name(type); // 注意：某些版本返回 char*            if (pTypeName) {                genericsName = pTypeName;                Buf = "[generics] name:";                Buf.append(pTypeName);                //LOG(LOG_LEVEL_INFO, "[Test MyStartPoint]%s", Buf.c_str());                writeLog(Buf);            }            // 填充类基础信息            AddClassStructInfo(pClassDataObj, name, genericsName, (uint64_t)klass);            // 存储当前类的 Il2CppClass 对象指针            pClassDataObj->m_pKlass = const_cast<Il2CppClass *>(klass);            // 5. 遍历字段 (Fields)            void* iter_field = nullptr;            while (auto field = il2cpp_class_get_fields(const_cast<Il2CppClass *>(klass), &iter_field)) {                const char* fieldName = il2cpp_field_get_name(field);                uint32_t offset = il2cpp_field_get_offset(field);                // 1. 获取字段属性标记                uint32_t attrs = il2cpp_field_get_flags(field);                Buf = "[Static Field] Name:";                Buf.append(fieldName);                writeLog(Buf);                //LOG(LOG_LEVEL_INFO, "[Test MyStartPoint]%s", Buf.c_str());                // 获取字段类型                const Il2CppType* type = il2cpp_field_get_type(field);                uint32_t typeType = type->type; // 或 il2cpp_type_get_type(type)                // 记录数据                AddVectorStaticData(pClassDataObj->m_pVectorStaticData, fieldName, field, (uint64_t)offset);            }            // 6. 遍历方法 (Methods)            void* iter_method = nullptr;            while (auto method = il2cpp_class_get_methods(const_cast<Il2CppClass *>(klass), &iter_method)) {                const char* methodName = il2cpp_method_get_name(method);                // 获取方法的虚地址（在内存中的地址）                uint64_t methodAddr = (uint64_t)method->methodPointer;                sprintf(szBuf,"%p",methodAddr);                //LOG(LOG_LEVEL_INFO, "    [Method] Name: %s, Addr: 0x%llX", methodName, methodAddr);                Buf = "[Method] Name: ";                Buf.append(methodName).append(" ").append(szBuf);                writeLog(Buf);                //LOG(LOG_LEVEL_INFO, "[Test MyStartPoint]%s", Buf.c_str());                AddVectorFunctionData(pClassDataObj->m_pVectorFunctionData, methodName, "", methodAddr);            }            // 7. 存入模块向量            pClassStructVec->push_back(*pClassDataObj);        }        // 8. 存入全局链表        AddClassStruct(m_pClassInfo, pModuleData, pClassStructVec);    }    LOG(LOG_LEVEL_INFO, "======== Class Info Filling Completed ========");}